import{_ as o,o as d,c as s,ai as c}from"./chunks/framework.CsYGeNYI.js";const u=JSON.parse('{"title":"OpenResponses Gateway 网关计划","description":"","frontmatter":{"last_updated":"2026-01-19","owner":"opensoul","status":"draft","summary":"计划：添加 OpenResponses /v1/responses 端点并干净地弃用 chat completions","title":"OpenResponses Gateway 网关计划","x-i18n":{"generated_at":"2026-02-03T07:47:33Z","model":"claude-opus-4-5","provider":"pi","source_hash":"71a22c48397507d1648b40766a3153e420c54f2a2d5186d07e51eb3d12e4636a","source_path":"experiments/plans/openresponses-gateway.md","workflow":15}},"headers":[],"relativePath":"zh-CN/experiments/plans/openresponses-gateway.md","filePath":"zh-CN/experiments/plans/openresponses-gateway.md","lastUpdated":null}'),t={name:"zh-CN/experiments/plans/openresponses-gateway.md"};function l(a,e,i,n,p,r){return d(),s("div",null,[...e[0]||(e[0]=[c('<h1 id="openresponses-gateway-网关集成计划" tabindex="-1"><a class="header-anchor" href="#openresponses-gateway-网关集成计划">#</a> OpenResponses Gateway 网关集成计划</h1><h2 id="背景" tabindex="-1"><a class="header-anchor" href="#背景">#</a> 背景</h2><p>OpenSoul Gateway 网关目前在 <code>/v1/chat/completions</code> 暴露了一个最小的 OpenAI 兼容 Chat Completions 端点（参见 <a href="/docs/gateway/openai-http-api">OpenAI Chat Completions</a>）。</p><p>Open Responses 是基于 OpenAI Responses API 的开放推理标准。它专为智能体工作流设计，使用基于项目的输入加语义流式事件。OpenResponses 规范定义的是 <code>/v1/responses</code>，而不是 <code>/v1/chat/completions</code>。</p><h2 id="目标" tabindex="-1"><a class="header-anchor" href="#目标">#</a> 目标</h2><ul><li>添加一个遵循 OpenResponses 语义的 <code>/v1/responses</code> 端点。</li><li>保留 Chat Completions 作为兼容层，易于禁用并最终移除。</li><li>使用隔离的、可复用的 schema 标准化验证和解析。</li></ul><h2 id="非目标" tabindex="-1"><a class="header-anchor" href="#非目标">#</a> 非目标</h2><ul><li>第一阶段完全实现 OpenResponses 功能（图片、文件、托管工具）。</li><li>替换内部智能体执行逻辑或工具编排。</li><li>在第一阶段更改现有的 <code>/v1/chat/completions</code> 行为。</li></ul><h2 id="研究摘要" tabindex="-1"><a class="header-anchor" href="#研究摘要">#</a> 研究摘要</h2><p>来源：OpenResponses OpenAPI、OpenResponses 规范网站和 Hugging Face 博客文章。</p><p>提取的关键点：</p><ul><li><code>POST /v1/responses</code> 接受 <code>CreateResponseBody</code> 字段，如 <code>model</code>、<code>input</code>（字符串或 <code>ItemParam[]</code>）、<code>instructions</code>、<code>tools</code>、<code>tool_choice</code>、<code>stream</code>、<code>max_output_tokens</code> 和 <code>max_tool_calls</code>。</li><li><code>ItemParam</code> 是以下类型的可区分联合： <ul><li>具有角色 <code>system</code>、<code>developer</code>、<code>user</code>、<code>assistant</code> 的 <code>message</code> 项</li><li><code>function_call</code> 和 <code>function_call_output</code></li><li><code>reasoning</code></li><li><code>item_reference</code></li></ul></li><li>成功响应返回带有 <code>object: &quot;response&quot;</code>、<code>status</code> 和 <code>output</code> 项的 <code>ResponseResource</code>。</li><li>流式传输使用语义事件，如： <ul><li><code>response.created</code>、<code>response.in_progress</code>、<code>response.completed</code>、<code>response.failed</code></li><li><code>response.output_item.added</code>、<code>response.output_item.done</code></li><li><code>response.content_part.added</code>、<code>response.content_part.done</code></li><li><code>response.output_text.delta</code>、<code>response.output_text.done</code></li></ul></li><li>规范要求： <ul><li><code>Content-Type: text/event-stream</code></li><li><code>event:</code> 必须匹配 JSON <code>type</code> 字段</li><li>终止事件必须是字面量 <code>[DONE]</code></li></ul></li><li>Reasoning 项可能暴露 <code>content</code>、<code>encrypted_content</code> 和 <code>summary</code>。</li><li>HF 示例在请求中包含 <code>OpenResponses-Version: latest</code>（可选头部）。</li></ul><h2 id="提议的架构" tabindex="-1"><a class="header-anchor" href="#提议的架构">#</a> 提议的架构</h2><ul><li>添加 <code>src/gateway/open-responses.schema.ts</code>，仅包含 Zod schema（无 gateway 导入）。</li><li>添加 <code>src/gateway/openresponses-http.ts</code>（或 <code>open-responses-http.ts</code>）用于 <code>/v1/responses</code>。</li><li>保持 <code>src/gateway/openai-http.ts</code> 不变，作为遗留兼容适配器。</li><li>添加配置 <code>gateway.http.endpoints.responses.enabled</code>（默认 <code>false</code>）。</li><li>保持 <code>gateway.http.endpoints.chatCompletions.enabled</code> 独立；允许两个端点分别切换。</li><li>当 Chat Completions 启用时发出启动警告，以表明其遗留状态。</li></ul><h2 id="chat-completions-弃用路径" tabindex="-1"><a class="header-anchor" href="#chat-completions-弃用路径">#</a> Chat Completions 弃用路径</h2><ul><li>保持严格的模块边界：responses 和 chat completions 之间不共享 schema 类型。</li><li>通过配置使 Chat Completions 成为可选，这样无需代码更改即可禁用。</li><li>一旦 <code>/v1/responses</code> 稳定，更新文档将 Chat Completions 标记为遗留。</li><li>可选的未来步骤：将 Chat Completions 请求映射到 Responses 处理器，以便更简单地移除。</li></ul><h2 id="第一阶段支持子集" tabindex="-1"><a class="header-anchor" href="#第一阶段支持子集">#</a> 第一阶段支持子集</h2><ul><li>接受 <code>input</code> 为字符串或带有消息角色和 <code>function_call_output</code> 的 <code>ItemParam[]</code>。</li><li>将 system 和 developer 消息提取到 <code>extraSystemPrompt</code> 中。</li><li>使用最近的 <code>user</code> 或 <code>function_call_output</code> 作为智能体运行的当前消息。</li><li>对不支持的内容部分（图片/文件）返回 <code>invalid_request_error</code> 拒绝。</li><li>返回带有 <code>output_text</code> 内容的单个助手消息。</li><li>返回带有零值的 <code>usage</code>，直到 token 计数接入。</li></ul><h2 id="验证策略-无-sdk" tabindex="-1"><a class="header-anchor" href="#验证策略-无-sdk">#</a> 验证策略（无 SDK）</h2><ul><li>为以下支持子集实现 Zod schema： <ul><li><code>CreateResponseBody</code></li><li><code>ItemParam</code> + 消息内容部分联合</li><li><code>ResponseResource</code></li><li>Gateway 网关使用的流式事件形状</li></ul></li><li>将 schema 保存在单个隔离模块中，以避免漂移并允许未来代码生成。</li></ul><h2 id="流式实现-第一阶段" tabindex="-1"><a class="header-anchor" href="#流式实现-第一阶段">#</a> 流式实现（第一阶段）</h2><ul><li>带有 <code>event:</code> 和 <code>data:</code> 的 SSE 行。</li><li>所需序列（最小可行）： <ul><li><code>response.created</code></li><li><code>response.output_item.added</code></li><li><code>response.content_part.added</code></li><li><code>response.output_text.delta</code>（根据需要重复）</li><li><code>response.output_text.done</code></li><li><code>response.content_part.done</code></li><li><code>response.completed</code></li><li><code>[DONE]</code></li></ul></li></ul><h2 id="测试和验证计划" tabindex="-1"><a class="header-anchor" href="#测试和验证计划">#</a> 测试和验证计划</h2><ul><li>为 <code>/v1/responses</code> 添加端到端覆盖： <ul><li>需要认证</li><li>非流式响应形状</li><li>流式事件顺序和 <code>[DONE]</code></li><li>使用头部和 <code>user</code> 的会话路由</li></ul></li><li>保持 <code>src/gateway/openai-http.e2e.test.ts</code> 不变。</li><li>手动：用 <code>stream: true</code> curl <code>/v1/responses</code> 并验证事件顺序和终止 <code>[DONE]</code>。</li></ul><h2 id="文档更新-后续" tabindex="-1"><a class="header-anchor" href="#文档更新-后续">#</a> 文档更新（后续）</h2><ul><li>为 <code>/v1/responses</code> 使用和示例添加新文档页面。</li><li>更新 <code>/gateway/openai-http-api</code>，添加遗留说明和指向 <code>/v1/responses</code> 的指针。</li></ul>',26)])])}const m=o(t,[["render",l]]);export{u as __pageData,m as default};
